<?php
namespace Tests\Feature;
use App\Models\Character;use App\Models\GameHomeCard;use Database\Seeders\CharacterLevelRequirementSeeder;use Database\Seeders\GameHomeCardSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class GameHomeTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);}public function test_home_is_ordered_clickable_responsive_and_uses_fallback(){$this->seed(GameHomeCardSeeder::class);$character=Character::factory()->selected()->create();$response=$this->actingAs($character->user)->get(route('dashboard'))->assertOk()->assertSeeInOrder(['Cambiar de PJ','Mi PJ','Mundo'])->assertSee(route('characters.overview',$character),false)->assertSee(route('worlds.index'),false)->assertSee('game-home-card__fallback',false)->assertSee('aspect-ratio:3/1',false)->assertDontSee('Abrir personaje');$this->assertSame(3,substr_count($response->getContent(),'class="game-home-card d-block'));}public function test_invalid_and_inactive_cards_are_omitted_without_breaking_home(){$this->seed(GameHomeCardSeeder::class);GameHomeCard::where('code','world')->update(['is_active'=>false]);GameHomeCard::create(['name'=>'Invalid card','code'=>'bad','destination_type'=>'unknown','destination_value'=>null,'sort_order'=>1,'is_active'=>true,'opens_new_tab'=>false]);$character=Character::factory()->selected()->create();$this->actingAs($character->user)->get('/')->assertOk()->assertDontSee('Invalid card')->assertDontSee('aria-label="Abrir Mundo"',false);}public function test_main_navigation_uses_overview_and_keeps_detailed_sheet(){$character=Character::factory()->selected()->create();$this->actingAs($character->user)->get('/')->assertOk()->assertSee(route('characters.overview',$character),false)->assertSee(route('characters.select'),false);$this->get(route('characters.show',$character))->assertOk();}}
